def evaluate_expression(expr: str) -> str:
    # Check if input contains only alphanumeric characters and spaces
    for char in expr:
        if not (char.isalnum() or char.isspace()):
            raise ValueError(f"Invalid character '{char}' found in expression")

    # Replace all digits with asterisks
    result = ""
    for char in expr:
        if char.isdigit():
            result += "*"
        else:
            result += char

    return result

turn2_code:
def evaluate_expression(expr: str) -> str:
    # Check if input contains only alphanumeric characters and spaces
    for char in expr:
        if not (char.isalnum() or char.isspace()):
            raise ValueError(f"Invalid character '{char}' found in expression")

    # Map digits to English words
    digit_words = {
        '0': 'zero',
        '1': 'one',
        '2': 'two',
        '3': 'three',
        '4': 'four',
        '5': 'five',
        '6': 'six',
        '7': 'seven',
        '8': 'eight',
        '9': 'nine'
    }

    # Process each character
    result = []
    for char in expr:
        if char.isdigit():
            result.append(digit_words[char])
        elif char.isalpha():
            result.append(char.upper())
        else:  # must be a space
            result.append(char)

    return ''.join(result)

turn3_code:
import re

def safe_eval_expression(expr: str) -> float:
    # Check if the expression contains only allowed characters
    # Allow digits, decimal points, operators (+, -, *, /, %), parentheses, and spaces
    if not re.match(r'^[0-9+\-*/().\s%]+$', expr):
        raise ValueError("Expression contains invalid characters")

    # Check for empty expression
    if not expr.strip():
        raise ValueError("Empty expression")

    # Additional safety checks
    # Check for invalid patterns like multiple operators in a row
    if re.search(r'[+\-*/]{2,}', expr):
        raise ValueError("Invalid operator sequence")

    # Check for invalid decimal points
    if re.search(r'\d*\.\d*\.', expr):
        raise ValueError("Invalid decimal number")

    try:
        # Use eval with restricted namespace for safety
        # Only allow basic math operations
        allowed_names = {
            '__builtins__': None,
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
        }

        result = eval(expr, {"__builtins__": {}}, allowed_names)

        # Ensure the result is a number
        if not isinstance(result, (int, float)):
            raise ValueError("Expression did not evaluate to a number")

        return float(result)

    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except Exception as e:
        raise ValueError(f"Invalid expression: {str(e)}")
